// Builds the Gemini generateContent request body.
// The prompt is versioned in n8n/prompts/invoice-extraction.md — keep both in sync.
const { mimeType, data } = $input.item.json;

const systemPrompt = `You are an expert accounts-payable data-entry specialist. You read supplier invoice documents and extract structured billing data with extreme care.

Rules:
1. Extract ONLY what is printed on the document. Never guess or infer values that are not visible.
2. If a field is absent or unreadable, return null. Null is always better than a guess.
3. Dates must be ISO format (YYYY-MM-DD). If a date like 03/04/2026 is ambiguous, use context such as written month names or date ordering to disambiguate; if still ambiguous, return null and add a warning.
4. Amounts are plain numbers without currency symbols or thousands separators.
5. currency is the 3-letter ISO 4217 code. Infer from a symbol only when unambiguous (a euro symbol means EUR). A bare dollar symbol could be USD, CAD, AUD or others - if no other clue exists, return null and add a warning.
6. vendorName is the party ISSUING the invoice (the supplier), never the bill-to party.
7. confidence is your honest overall probability (0 to 1) that every extracted field is correct. Blur, handwriting, unusual layouts, or any guesswork must lower it.
8. warnings: short notes on anything a human reviewer should double-check.`;

const responseSchema = {
  type: 'OBJECT',
  properties: {
    vendorName: { type: 'STRING', nullable: true, description: 'Supplier issuing the invoice, exactly as printed' },
    invoiceNumber: { type: 'STRING', nullable: true },
    invoiceDate: { type: 'STRING', nullable: true, description: 'YYYY-MM-DD' },
    dueDate: { type: 'STRING', nullable: true, description: 'YYYY-MM-DD' },
    currency: { type: 'STRING', nullable: true, description: 'ISO 4217 code, e.g. USD' },
    subtotal: { type: 'NUMBER', nullable: true },
    tax: { type: 'NUMBER', nullable: true },
    total: { type: 'NUMBER', nullable: true },
    confidence: { type: 'NUMBER', description: 'Overall confidence between 0 and 1' },
    warnings: { type: 'ARRAY', items: { type: 'STRING' } }
  },
  required: ['vendorName', 'invoiceNumber', 'invoiceDate', 'dueDate', 'currency', 'subtotal', 'tax', 'total', 'confidence', 'warnings']
};

return [{
  json: {
    geminiRequest: {
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents: [{
        role: 'user',
        parts: [
          { inline_data: { mime_type: mimeType, data } },
          { text: 'Extract the structured billing data from this invoice document.' }
        ]
      }],
      generationConfig: {
        temperature: 0,
        response_mime_type: 'application/json',
        response_schema: responseSchema
      }
    }
  }
}];

// Unwraps Gemini's response envelope into our internal report shape.
const response = $input.item.json;
const candidate = response.candidates?.[0];
const text = candidate?.content?.parts?.[0]?.text;
if (!text) {
  throw new Error(`Gemini returned no text (finishReason: ${candidate?.finishReason ?? 'unknown'})`);
}
const parsed = JSON.parse(text);
const { confidence, warnings, ...fields } = parsed;
return [{ json: { outcome: 'success', data: fields, confidence, warnings: warnings ?? [], n8nExecutionId: $execution.id } }];

// Canonical text: the invoice's identity distilled to one line.
// Embedding THIS (not the whole document) makes near-duplicates cluster
// tightly: same vendor/number/date/total => nearly identical vectors,
// even when scans or extractions differ slightly.
const d = $input.item.json.data;
const canonical = [
  d.vendorName,
  d.invoiceNumber,
  d.invoiceDate,
  d.total != null ? Number(d.total).toFixed(2) : null,
  d.currency
].map(v => v ?? 'unknown').join(' | ').toLowerCase();

return [{
  json: {
    embedRequest: {
      model: 'models/gemini-embedding-001',
      content: { parts: [{ text: canonical }] },
      outputDimensionality: 768
    },
    canonical
  }
}];

// Merge the embedding into the extraction report. An embedding failure
// (onError: continueRegularOutput upstream) yields null — the app treats
// that as degraded duplicate protection, not a fatal error.
const report = $('Parse extraction').item.json;
const values = $input.item.json.embedding?.values ?? null;
return [{ json: { ...report, embedding: values } }];

// The Gemini call errored (auth, rate limit, network). Convert the error
// into a failure report so the app can mark the invoice FAILED instead of
// leaving it stuck in EXTRACTING forever.
const item = $input.item.json;
const message =
  item.error?.message ??
  item.error?.description ??
  (typeof item.error === 'string' ? item.error : JSON.stringify(item).slice(0, 800));
return [{ json: { outcome: 'failure', error: `Gemini request failed: ${message}`, n8nExecutionId: $execution.id } }];
